        {
            return definition.GetProperty<bool>(BLOCKS_JUMP);
        }
        #endregion

        #region 地板器械
        public static readonly PropertyMeta<bool> IS_FLOOR = Get<bool>("isFloor");
        public static bool IsFloor(this Entity contraption)
