        public static readonly PropertyMeta<NamespaceID> FRAGMENT_ID = Get<NamespaceID>("fragmentId");
        public static NamespaceID? GetFragmentID(this Entity entity) => entity.GetProperty<NamespaceID>(FRAGMENT_ID);
